auth.verifyScript:
(function () {
  try {
    var currentUrl = location.href;
    if (currentUrl.indexOf('SSO/Main.aspx') !== -1) {
      var links = document.querySelectorAll('a');
      var foundTarget = false;
      for (var i = 0; i < links.length; i++) {
        var text = links[i].textContent.trim();
        if (text.indexOf('修課紀錄') !== -1 || text.indexOf('校務系統') !== -1) {
          foundTarget = true;
          break;
        }
      }
      var bridge = window.mobileApp || (window.webkit && window.webkit.messageHandlers && window.webkit.messageHandlers.mobileApp);
      if (bridge) {
        bridge.postMessage({ detail: { type: 'AUTH_SUCCESS' }});
      }
    }
  } catch (e) {}
})();

schedule.parseScript:
(function() {
  if (window.isProcessing) return;

  var container = document.getElementById('TabPanel2');
  var table = container ? container.querySelector('table') : null;
  if (!table) return;

  window.isProcessing = true;
  var result = [];
  var slotMap = ['1', '2', '3', '4', '5', '6', '7', '8'];

  for (var k = 0; k < slotMap.length; k++) {
    result.push({
      slot: slotMap[k],
      days: [{}, {}, {}, {}, {}]
    });
  }

  var rows = table.querySelectorAll('tbody tr');
  var dataIndex = 0;

  for (var i = 0; i < rows.length; i++) {
    var tr = rows[i];
    var cols = tr.querySelectorAll('td.course-cell');

    if (cols.length >= 5 && dataIndex < result.length) {
      var currentSlot = result[dataIndex];

      for (var d = 0; d < 5; d++) {
        var cell = cols[d];
        var div = cell.querySelector('.course-text');
        var text = div ? div.innerText.trim() : cell.innerText.trim();

        if (text.length > 0) {
          currentSlot.days[d] = {
            name: text,
            room: '',
            teacher: ''
          };
        }
      }
      dataIndex++;
    }
  }

  if (window.mobileApp) {
    window.mobileApp.postMessage({
      detail: { type: 'DATA_SUCCESS', payload: result }
    });
  }
})();

schedule.manualParseScript:
(function() {
    if (window._hasSentData) return;

    function getTableById(id) {
        if (document.getElementById(id)) return document.getElementById(id);
        const iframes = document.querySelectorAll('iframe');
        for (let f of iframes) {
            try {
                const fDoc = f.contentDocument || f.contentWindow.document;
                const target = fDoc.getElementById(id);
                if (target) return target;
            } catch (e) {}
        }
        return null;
    }

    const table = getTableById('GrdStd2');
    if (!table) return;

    window._hasSentData = true;

    const result = [];
    const rows = table.querySelectorAll('tr.tblContent');

    rows.forEach(tr => {
        const tds = Array.from(tr.querySelectorAll('td'));
        if (tds.length < 6) return;

        const slotVal = tds[0].innerText.trim();
        if (!/^[1-8]$/.test(slotVal) && slotVal !== "午休") return;

        const rowData = {
            slot: slotVal,
            days: []
        };

        for (let d = 1; d <= 7; d++) {
            const cell = tds[d];
            const box = cell ? cell.querySelector('.ctrlboxlessV') : null;

            if (box) {
                const info = Array.from(box.querySelectorAll('div')).map(el => el.innerText.trim()).filter(s => s !== "");

                if (info.length > 0) {
                    const subject = info[0];
                    let teacher = "";
                    let roomParts = [];

                    for (let i = 1; i < info.length; i++) {
                        const text = info[i];
                        if (text.includes("班") || text.includes("教室") || text.includes("電腦")) {
                            roomParts.push(text);
                        } else if (teacher === "") {
                            teacher = text;
                        }
                    }

                    rowData.days.push({
                        name: subject,
                        room: roomParts.join(' '),
                        teacher: teacher
                    });
                } else {
                    rowData.days.push({});
                }
            } else {
                rowData.days.push({});
            }
        }
        result.push(rowData);
    });

    if (window.mobileApp && window.mobileApp.postMessage) {
        window.mobileApp.postMessage({
            detail: { type: 'DATA_SUCCESS', payload: result }
        });
    }

    console.log(result);
})();

score.switchScript:
(function () {
    // 1. 設定目標學期（App 應將 {{TARGET_TERM}} 替換為「二下」或「一上」等）
    var targetTerm = '{{TARGET_TERM}}'.replace('-', '').trim();

    // 2. 防重複執行鎖（避免在頁面載入中重複觸發導致死循環）
    if (window._isSwitchingLock && (Date.now() - window._isSwitchingLock < 3000)) return;
    window._isSwitchingLock = Date.now();

    // 3. 穿透搜尋函數（支援 iframe 結構）
    function getElement(selector) {
        let el = document.querySelector(selector);
        if (el) return el;
        for (let i = 0; i < window.frames.length; i++) {
            try {
                let fDoc = window.frames[i].document;
                el = fDoc.querySelector(selector);
                if (el) return el;
            } catch (e) {}
        }
        return null;
    }

    // 定位選單
    var sel = getElement('#DdlStd_yearterm_ddl') || getElement('select[name="DdlStd_yearterm_ddl"]');

    if (!sel) {
        console.error("找不到學期選單 DdlStd_yearterm_ddl");
        window._isSwitchingLock = 0;
        return;
    }

    var currentText = sel.options[sel.selectedIndex].text.trim();

    // --- 判斷邏輯 ---

    // A. 已經在目標學期 -> 執行解析資料
    if (currentText.includes(targetTerm) || targetTerm.includes(currentText)) {
        console.log("目前已在目標學期：" + currentText + "，準備解析資料...");
        if (typeof parseAndSendData === "function") {
            parseAndSendData(currentText);
        } else {
            console.log("請配合成績解析腳本使用。");
        }
    } 
    // B. 需要切換學期 -> 執行自動切換
    else {
        var foundIndex = -1;
        for (var i = 0; i < sel.options.length; i++) {
            var optText = sel.options[i].text.trim();
            if (optText.includes(targetTerm) || targetTerm.includes(optText)) {
                foundIndex = i;
                break;
            }
        }

        if (foundIndex !== -1) {
            console.log("正在從 " + currentText + " 切換至 " + targetTerm);
            sel.selectedIndex = foundIndex;

            // 觸發 ASP.NET 內建的 ddlchange(this) 邏輯
            var onchangeAttr = sel.getAttribute('onchange');
            if (onchangeAttr) {
                // 強制將 this 綁定在 sel 執行，確保觸發 __doPostBack
                new Function(onchangeAttr).call(sel);
            } else if (typeof sel.onchange === 'function') {
                sel.onchange();
            } else {
                // 備援方案：手動派發 Change 事件
                var evt = document.createEvent("HTMLEvents");
                evt.initEvent("change", true, true);
                sel.dispatchEvent(evt);
            }
        } else {
            console.error("選單中找不到目標學期：" + targetTerm);
            window._isSwitchingLock = 0;
        }
    }
})();

score.parseScript:
(function() {
    // 1. 防止重複執行
    if (window._hasParsedGrades) return;

    var findInAllContexts = function(selector, callback) {
        var result = callback(document.querySelector(selector), document);
        if (result) return result;

        var frames = document.querySelectorAll('iframe, frame');
        for (var i = 0; i < frames.length; i++) {
            try {
                var fDoc = frames[i].contentDocument || frames[i].contentWindow.document;
                result = callback(fDoc.querySelector(selector), fDoc);
                if (result) return result;
            } catch (e) {}
        }
        return null;
    };

    // 2. 精確獲取當前選中的學期標籤 (如：二下)
    var termLabel = findInAllContexts('#DdlStd_yearterm_ddl', function(sel) {
        if (sel && sel.options[sel.selectedIndex]) {
            return sel.options[sel.selectedIndex].text.trim();
        }
        return null;
    }) || "未知學期";

    // 3. 定位成績表格 (以包含 "科目" 與 "學分" 的表格為準)
    var targetTable = findInAllContexts('table', function(table, doc) {
        var allTables = doc.querySelectorAll('table');
        for (var i = 0; i < allTables.length; i++) {
            var text = allTables[i].innerText;
            // 同時檢查 科目 與 學期/期末 關鍵字，確保抓對表格
            if (text.indexOf('科目') > -1 && (text.indexOf('學期成績') > -1 || text.indexOf('評量') > -1)) {
                return allTables[i];
            }
        }
        return null;
    });

    if (!targetTable) {
        console.error("找不到成績表格");
        return;
    }

    var res = [];
    var rows = targetTable.querySelectorAll('tr');

    rows.forEach(function(tr) {
        var tds = tr.querySelectorAll('td');
        // 鳳商表格通常 科目在第0欄，學分在第1欄，學期成績在最後一欄
        if (tds.length >= 5) { 
            var subject = tds[0].innerText.trim();
            var credit = tds[1].innerText.trim();
            // 抓取最後一欄作為學期成績
            var scoreText = tds[tds.length - 1].innerText.trim();

            // 過濾掉表頭列與空列
            if (subject && subject !== "科目" && !isNaN(parseFloat(credit))) {
                var scoreNum = parseFloat(scoreText);
                var isPass = !isNaN(scoreNum) ? scoreNum >= 60 : false;

                // 處理非數字成績 (如：未結算)
                var displayScore = scoreText === "" ? "未結算" : scoreText;

                res.push({
                    term: termLabel,       // 學期 (二下)
                    subject: subject,      // 科目名稱
                    credit: credit,        // 學分數
                    score: displayScore,   // 分數
                    isPass: isPass,        // 是否及格
                    status: isPass ? '及格' : (isNaN(scoreNum) ? '-' : '不及格')
                });
            }
        }
    });

    // 4. 回傳 App
    if (res.length > 0) {
        window._hasParsedGrades = true;
        console.log("解析成功，共 " + res.length + " 筆成績：", res);

        if (window.mobileApp && typeof window.mobileApp.postMessage === 'function') {
            // 強制轉字串，避免 App 接收端出現 undefined
            window.mobileApp.postMessage(JSON.stringify({ 
                detail: { type: 'DATA_SUCCESS', payload: res } 
            }));
        }
    }
})();

news.webviewScript:
if (window._hasParsedNews) return;
var rows = document.querySelectorAll('.table-list tbody tr, table tr');
var payload = [];
if (rows.length > 0) {
    rows.forEach(function(tr) {
        var dateEl = tr.querySelector('.d-txt, .mdate') || (tr.cells ? tr.cells[0] : null);
        var titleContainer = tr.querySelector('.mtitle') || (tr.cells ? tr.cells[1] : null);
        var linkEl = titleContainer ? titleContainer.querySelector('a') : null;
        if (titleContainer) {
            var titleText = titleContainer.textContent.trim();
            if (titleText && titleText !== "標題" && titleText !== "主題") {
                payload.push({
                    title: titleText,
                    department: "校內公告",
                    date: dateEl ? dateEl.textContent.trim() : '',
                    link: linkEl ? linkEl.href : window.location.href
                });
            }
        }
    });
    if (payload.length > 0) {
        window._hasParsedNews = true;
        window.mobileApp.postMessage({ 
            detail: { 
                type: 'NEWS_SUCCESS', 
                payload: payload 
            } 
        });
    }
}
